INSERT INTO public.question_bank_questions (product_slug, bank_type, category, question, options, correct_answer, explanation, sort_order) VALUES
('pro-achiever','exam','suitability','Which client is most suitable for Pro Achiever 3.0?','["A client who needs the money within 2 years","A client with stable income and a long-term investment horizon","A client who wants guaranteed yearly returns","A client who prefers full liquidity at all times"]'::jsonb,1,'Pro Achiever is a long-term ILP and is more suitable for clients who can commit consistently and are comfortable with market fluctuations over time.',36),
('pro-achiever','exam','suitability','Which client is least suitable for Pro Achiever 3.0?','["A young professional building long-term wealth","A parent planning for a child''s future","A client who plans to use the money for a property downpayment in 3 years","A client comfortable with volatility"]'::jsonb,2,'Short-term financial goals are generally not aligned with long-term ILPs due to surrender charges and market volatility.',37),
('pro-achiever','exam','suitability','What is the most important factor when recommending Pro Achiever?','["The welcome bonus percentage","The client''s ability to sustain premiums and time horizon","The fund performance history","The advisor''s closing rate"]'::jsonb,1,'Suitability depends primarily on whether the client can sustain the plan and whether it fits their long-term goals.',38),
('pro-achiever','exam','suitability','A client says: "I don''t like seeing my investments drop." What should you do?','["Proceed anyway because of bonuses","Reassess suitability and explain market fluctuations","Increase premium to offset volatility","Recommend only GDIF"]'::jsonb,1,'Pro Achiever is market-linked. If the client cannot tolerate volatility, the plan may not be suitable unless expectations are reset.',39),
('pro-achiever','exam','suitability','A client wants to invest all their savings into Pro Achiever. What is the best response?','["Agree to maximize growth","Recommend splitting between emergency, short-term, and long-term funds","Encourage higher premium for better bonus","Suggest adding riders instead"]'::jsonb,1,'Proper financial planning separates liquidity needs from long-term investments.',40),
('pro-achiever','exam','suitability','When might Pro Achiever NOT be suitable?','["When the client has long-term goals","When the client has stable income","When the client needs high liquidity in the short term","When the client wants diversification"]'::jsonb,2,'Short-term liquidity needs conflict with ILP structure and surrender charges.',41),
('pro-achiever','exam','compliance','Which statement should an advisor avoid?','["Returns are not guaranteed.","We should see if this fits your goals first.","This plan guarantees you will make money long-term.","This is a long-term commitment."]'::jsonb,2,'ILPs do not guarantee returns. This statement is misleading and non-compliant.',42),
('pro-achiever','exam','compliance','A client asks if returns in the illustration are guaranteed. What is the correct response?','["Yes, guaranteed by AIA","No, returns depend on fund performance","Yes, if held long enough","Only the bonus is guaranteed"]'::jsonb,1,'Fund performance is not guaranteed and must be explained clearly.',43),
('pro-achiever','exam','compliance','A client says: "Can I use this as my emergency fund?" What is the correct response?','["Yes, it''s flexible","No, it should be used for long-term investing","Yes, because of Premium Pass","Only after 10 years"]'::jsonb,1,'ILPs are not suitable as emergency funds due to liquidity and market risks.',44),
('pro-achiever','exam','compliance','Which is the most appropriate way to describe Pro Achiever?','["This is suitable for everyone","This is a long-term investment plan that may suit the right client","This guarantees wealth accumulation","This replaces all other investments"]'::jsonb,1,'This is balanced and avoids over-promising.',45),
('pro-achiever','exam','advisory-skills','What is the best first question before pitching Pro Achiever?','["How much do you want to invest?","What are your long-term financial goals?","Do you want high returns?","Do you like bonuses?"]'::jsonb,1,'Understanding goals is critical before recommending any solution.',46),
('pro-achiever','exam','advisory-skills','A client already invests in ETFs. What is the best advisor mindset?','["Replace ETFs immediately","Show how Pro Achiever complements existing investments","Criticize ETFs","Ignore existing investments"]'::jsonb,1,'Strong advisors position products as complementary, not replacements.',47),
('pro-achiever','exam','advisory-skills','A client asks: "Why should I invest through you?" What is the best response?','["Because I have better products","Because I provide structured planning, discipline, and long-term guidance","Because I work with AIA","Because of bonuses"]'::jsonb,1,'Advisors sell value, not just products.',48),
('pro-achiever','exam','advisory-skills','Which behavior shows strong advisory practice?','["Pushing for the highest premium","Matching product recommendation to client needs","Closing quickly before objections","Avoiding difficult questions"]'::jsonb,1,'Suitability and alignment are key to professional advisory.',49),
('pro-achiever','exam','advisory-skills','A client says: "I want to invest but not commit long-term." What should you do?','["Push Pro Achiever anyway","Recommend alternative solutions or adjust expectations","Increase premium","Ignore concern"]'::jsonb,1,'Not all clients are suitable. Advisors must be willing to walk away or adjust.',50),
('pro-achiever','exam','closing','A client says: "I''ll think about it." What is the best response?','["Accept and wait","Ask what specifically they want to think about and set a follow-up","Pressure them to sign","Send brochure"]'::jsonb,1,'This uncovers hidden objections and keeps momentum.',51),
('pro-achiever','exam','closing','A client says: "I like it but I''m not ready." What is the best next step?','["Push urgency","Clarify what is holding them back and address it","End meeting","Reduce premium immediately"]'::jsonb,1,'Good closing identifies and resolves hesitation.',52),
('pro-achiever','exam','closing','A client wants to review finances first. What is the best response?','["Start first, review later","Let''s review your finances together and decide comfortably","It''s not necessary","Just commit minimum"]'::jsonb,1,'Advisors guide decision-making, not rush it.',53),
('pro-achiever','exam','closing','A client says: "Send me details." What is best practice?','["Send PDF only","Send summary + schedule follow-up","Wait for reply","Send daily reminders"]'::jsonb,1,'Always control the follow-up process.',54),
('pro-achiever','exam','closing','A client says: "I need to discuss with my spouse." What is best response?','["Decide yourself","Let''s arrange a session together so both can understand","That will delay things","Sign first"]'::jsonb,1,'Involving decision-makers improves conversion and trust.',55),
('pro-achiever','exam','roleplay','A client says: "Why shouldn''t I just do Buy Term Invest the Rest?" What is the best response?','["BTIR doesn''t work","APA structures discipline, provides bonuses, and integrates protection with investment — which many people struggle to do consistently themselves","BTIR is illegal","APA always performs better"]'::jsonb,1,'This acknowledges BTIR as valid while differentiating APA properly.',56),
('pro-achiever','exam','roleplay','A client says: "What if the market crashes right after I start?" What is the best answer?','["It won''t happen","Short-term volatility is normal — regular premiums allow you to buy more units at lower prices, which helps long-term outcomes","You''ll lose money","AIA will cover losses"]'::jsonb,1,'This explains DCA and long-term investing clearly.',57),
('pro-achiever','exam','advisory-skills','What separates a top advisor from an average one when selling Pro Achiever?','["Memorizing bonus structures","Understanding client psychology and matching solutions to real needs","Selling highest premium","Avoiding objections"]'::jsonb,1,'Top advisors focus on people, not just products.',58),
('pro-achiever','exam','suitability','A client earns well but plans to start a business in 2 years. What should you do?','["Recommend maximum premium","Consider lower commitment or defer decision","Ignore future plans","Push urgency"]'::jsonb,1,'Future cash flow uncertainty must be considered in suitability.',59);